      -- 检查是否有SUPERWOW_STRING，没有则禁止勾选
      if not SUPERWOW_STRING then
        -- 恢复未勾选状态
        this:SetChecked(false)
        return
      end

      -- 获取当前复选框状态
      local isChecked = this:GetChecked()

      -- 更新WebDKP_SubData状态
      WebDKP_SubData.useCheckIn = isChecked

      -- 同步状态到Boss击杀窗口
      if WebDKP_BossAwardFrame and WebDKP_BossAwardFrame.useCheckInCheckButton then
        WebDKP_BossAwardFrame.useCheckInCheckButton:SetChecked(isChecked)
      end

      -- 保存设置到WebDKP_Options
      if WebDKP_Options and WebDKP_Options["SubSettings"] then
        WebDKP_Options["SubSettings"]["useCheckIn"] = isChecked
      end

      -- 更新WebDKP_SubAwardData状态
      if WebDKP_SubAwardData then
        WebDKP_SubAwardData.useCheckIn = isChecked
      end

      -- 同步状态到WebDKP_BossAwardData
      if WebDKP_BossAwardData then
        WebDKP_BossAwardData.useCheckIn = isChecked
      end

      -- 保存设置
      WebDKP_SaveSubSettings()

      -- 更新队长标签显示
      WebDKP_UpdateCaptainLabel()


      -- 检查是否有SUPERWOW_STRING，没有则禁用并隐藏
      if not SUPERWOW_STRING then
        this:SetChecked(false)
        this:Hide()
        return
      end

      this:SetText("打卡");
      if WebDKP_SubAwardData and WebDKP_SubAwardData.useCheckIn ~= nil then
        this:SetChecked(WebDKP_SubAwardData.useCheckIn);
      end



























































































































































